import{_ as t,o as r,c as s,ag as o}from"./chunks/framework.WmBmIPw-.js";const d=JSON.parse('{"title":"禁忌搜索（Tabu Search, TS）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/tabu-search.md","filePath":"or-opt/tabu-search.md","lastUpdated":1777118660000}'),e={name:"or-opt/tabu-search.md"};function n(l,a,i,h,c,g){return r(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="禁忌搜索-tabu-search-ts" tabindex="-1">禁忌搜索（Tabu Search, TS） <a class="header-anchor" href="#禁忌搜索-tabu-search-ts" aria-label="Permalink to &quot;禁忌搜索（Tabu Search, TS）&quot;">​</a></h1><p>禁忌搜索在<strong>邻域搜索</strong>框架上引入<strong>短期记忆（禁忌表）</strong>：将近期执行过的「移动」或其<strong>属性</strong>（如被交换的边、被翻转的变量下标等）列为<strong>禁忌</strong>，在一定步数内禁止立即回退，以避免在局部最优附近来回震荡。可配合<strong>渴望准则</strong>（aspiration）在禁忌移动仍带来历史最优时破禁。属于单点、带记忆的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：组合优化（TSP、调度、图着色等）的近似求解；邻域与<strong>移动属性</strong>的定义对效果影响大。</p><p><strong>核心</strong>：每步在（经渴望过滤后的）<strong>可接受邻域</strong>中选使目标改进或「最不坏」的移动；禁忌表按** tenure**（禁忌步长）滑动更新，常取近优解、多邻域与重启。</p><hr><h2 id="算法-最小化示意" tabindex="-1">算法（最小化示意） <a class="header-anchor" href="#算法-最小化示意" aria-label="Permalink to &quot;算法（最小化示意）&quot;">​</a></h2><p>以目标函数 f(s) 最小化叙述；禁忌对象记为与<strong>移动</strong>关联的<strong>属性</strong> a（实现上常用属性集合 A，对选中的移动更新 A）。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 禁忌搜索主循环（单解、邻域 + 禁忌表）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>选定初始解 s（随机或启发式），记历史最优 s⋆ ← s。初始化<strong>空</strong>禁忌结构（如记录最近禁止的属性及剩余禁忌步数），设定参数：邻域算子、禁忌步长（tenure）、最大迭代、无改进步数等。</p><h3 id="_2-邻域与筛选" tabindex="-1">2. 邻域与筛选 <a class="header-anchor" href="#_2-邻域与筛选" aria-label="Permalink to &quot;2. 邻域与筛选&quot;">​</a></h3><p>当前解为 s。由邻域算子生成候选集 N(s)（或采样子集）。对每个候选移动 m：得到 s′ = m(s)，计算 f(s′)。若 m 对应属性在禁忌期内，则 m 一般<strong>不可选</strong>，除非满足<strong>渴望准则</strong>（例如 f(s′) &lt; f(s⋆)，即破禁能带来新的历史最优）。</p><h3 id="_3-选择与移动" tabindex="-1">3. 选择与移动 <a class="header-anchor" href="#_3-选择与移动" aria-label="Permalink to &quot;3. 选择与移动&quot;">​</a></h3><p>在<strong>可接受</strong>的候选中，按预定规则选取一步（常见：若存在改进移动则选最优改进；否则选<strong>最小增</strong>的恶化移动以离开局部）。执行该移动，更新 s。</p><h3 id="_4-更新禁忌与全局最优" tabindex="-1">4. 更新禁忌与全局最优 <a class="header-anchor" href="#_4-更新禁忌与全局最优" aria-label="Permalink to &quot;4. 更新禁忌与全局最优&quot;">​</a></h3><p>将该步所涉<strong>属性</strong>记入禁忌表，并赋予剩余禁忌步数为 tenure（常可随迭代或随机微扰）。若 f(s) &lt; f(s⋆)，令 s⋆ ← s。</p><h3 id="_5-终止" tabindex="-1">5. 终止 <a class="header-anchor" href="#_5-终止" aria-label="Permalink to &quot;5. 终止&quot;">​</a></h3><p>达到迭代/时间上限、或长期无改进（带可能的重启策略）等，则停；输出 s⋆。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><ul><li><strong>移动与属性</strong>：禁忌可针对「边」、「位置对」、「变量_flip」等；需与邻域定义一致，否则表意不清。</li><li><strong>Tenure</strong>：过短则仍易循环；过长则过度限制探索。常与问题规模、邻域大小联调。</li><li><strong>渴望准则</strong>：典型为「优于当前历史最优则破禁」，避免错过好的解。</li><li><strong>长期策略</strong>（可选）：频率惩罚、强化/分散、多邻域切换等，在此不展开。</li></ul><h2 id="参考阅读" tabindex="-1">参考阅读 <a class="header-anchor" href="#参考阅读" aria-label="Permalink to &quot;参考阅读&quot;">​</a></h2><ul><li>Glover: Tabu Search 系列工作；教材与综述中均有系统整理。</li><li>实现需为具体问题的<strong>解编码、邻域、属性提取</strong>单独设计。</li></ul>',13)])])}const p=t(e,[["render",n]]);export{d as __pageData,p as default};
